<template>
  <div class="chat-box border rounded-3 p-3 h-100 d-flex flex-column" style="height: 600px !important;">
    <!-- 对话内容区域 -->
    <div class="chat-content flex-grow-1 overflow-auto mb-3" id="chatContent">
      <!-- 机器人欢迎语 -->
      <div class="d-flex mb-3 justify-content-start">
        <div class="bg-light rounded-3 p-3 shadow-sm max-w-75">
          你好～我是校园生活小管家，有什么可以帮你的？<br>
          试试问我：<span class="text-primary">今日课表</span>、<span class="text-primary">食堂吃什么</span>、<span class="text-primary">报修电话是多少</span>、<span class="text-primary">下课后提醒我取快递</span>
        </div>
      </div>
    <!-- 对话消息列表 -->
    <div v-for="(msg, index) in msgList" :key="index" class="d-flex mb-3" :class="msg.isUser ? 'justify-content-end' : 'justify-content-start'">
      <div :class="msg.isUser ? 'bg-primary text-white rounded-3 p-3 shadow-sm max-w-75' : 'bg-light rounded-3 p-3 shadow-sm max-w-75'">
        <!-- 用户消息：文本+图片预览+文档；AI消息：支持markdown渲染 -->
        <template v-if="msg.isUser">
          <!-- 图片预览（多图） -->
          <div v-if="msg.images && msg.images.length > 0" class="mb-2 d-flex flex-wrap gap-2">
            <img v-for="(img, idx) in msg.images" :key="idx" :src="img" class="rounded img-thumbnail" style="max-width: 150px; max-height: 150px; cursor: pointer;" @click="previewImage(img)" />
          </div>
          <!-- 文档预览 -->
          <div v-if="msg.docs && msg.docs.length > 0" class="mb-2">
            <div v-for="(doc, idx) in msg.docs" :key="idx" class="d-flex align-items-center gap-2 bg-white bg-opacity-25 rounded px-2 py-1 mb-1">
              <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="currentColor" viewBox="0 0 16 16">
                <path d="M14 4.5V14a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2h5.5L14 4.5zm-3 0A1.5 1.5 0 0 1 9.5 3V1H4a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1V4.5h-2z"/>
              </svg>
              <span style="font-size: 12px;">{{ doc.name }}</span>
            </div>
          </div>
          <div>{{ msg.content }}</div>
        </template>
        <div v-else class="ai-msg-content" v-html="renderMarkdown(msg.content)"></div>
        <!-- 结果卡片：课表/提醒/知识库 -->
        <ResultCard v-if="msg.data" :data="msg.data" :intent="msg.intent" />
      </div>
    </div>
    <!-- 图片预览模态框 -->
    <div v-if="previewSrc" class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.7); z-index: 9999;" @click.self="previewSrc = null">
      <div class="modal-dialog modal-dialog-centered modal-fullscreen d-flex align-items-center justify-content-center m-0">
        <img :src="previewSrc" class="img-fluid rounded" style="max-width: 90vw; max-height: 90vh;" @click="previewSrc = null" />
        <button type="button" class="btn-close btn-close-white position-absolute" style="top: 20px; right: 20px;" @click="previewSrc = null"></button>
      </div>
    </div>
  </div>
    <!-- 已选文件预览区 -->
    <div v-if="selectedImages.length > 0 || selectedDocs.length > 0" class="mb-2 d-flex flex-wrap gap-2 align-items-center">
      <!-- 图片预览 -->
      <div v-for="(img, index) in selectedImages" :key="'img-'+index" class="position-relative">
        <img :src="img" class="rounded" style="width: 60px; height: 60px; object-fit: cover; cursor: pointer;" @click="previewImage(img)" />
        <button type="button" class="btn-close position-absolute" style="top: -5px; right: -5px; font-size: 10px; background: #fff; border-radius: 50%; padding: 2px;" @click="removeImage(index)"></button>
      </div>
      <!-- 文档预览 -->
      <div v-for="(doc, index) in selectedDocs" :key="'doc-'+index" class="d-flex align-items-center gap-2 bg-light rounded px-2 py-1">
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="currentColor" class="text-secondary" viewBox="0 0 16 16">
          <path d="M14 4.5V14a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2h5.5L14 4.5zm-3 0A1.5 1.5 0 0 1 9.5 3V1H4a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1V4.5h-2z"/>
        </svg>
        <span class="text-truncate" style="max-width: 100px; font-size: 12px;">{{ doc.name }}</span>
        <button type="button" class="btn-close" style="font-size: 8px;" @click="removeDoc(index)"></button>
      </div>
    </div>
    <!-- 输入框区域 -->
    <div class="input-group">
      <!-- 回形针上传按钮（带徽标） -->
      <div class="position-relative">
        <button class="btn btn-outline-secondary" type="button" title="上传图片或文件" @click="triggerUpload">
          <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="currentColor" viewBox="0 0 16 16">
            <path d="M4.5 3a2.5 2.5 0 0 1 5 0v9a1.5 1.5 0 0 1-3 0V5a.5.5 0 0 1 1 0v9a3 3 0 0 0 6 0V5a.5.5 0 0 1 1 0v9a4 4 0 0 1-8 0V3z"/>
            <path d="M9.5 1H4a2 2 0 0 0-2 2v9a2 2 0 0 0 2 2h5.5a.5.5 0 0 0 0-1H4a1 1 0 0 1-1-1V3a1 1 0 0 1 1-1h5.5a.5.5 0 0 0 0-1H9.5z"/>
          </svg>
        </button>
        <!-- 已选文件数量徽标 -->
        <span v-if="totalSelectedCount > 0" class="position-absolute top-0 start-100 translate-middle badge rounded-pill bg-danger" style="font-size: 10px;">
          {{ totalSelectedCount }}
        </span>
      </div>
      <!-- 隐藏的文件上传input -->
      <input ref="uploadInput" type="file" multiple accept="image/*,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.pdf" style="display: none;" @change="handleFileUpload" />
      <input v-model="inputContent" type="text" class="form-control" placeholder="请输入你的问题..." @keyup.enter="sendMsg">
      <button class="btn btn-primary" type="button" @click="sendMsg">发送</button>
    </div>
  </div>
</template>

<script>
import ResultCard from './ResultCard.vue'
export default {
  name: 'ChatBox',
  components: { ResultCard },
  data() {
    return {
      inputContent: '',      // 输入内容
      msgList: [],           // 消息列表
      userId: 1,             // 测试用户ID，可扩展为登录后获取
      selectedImages: [],    // 已选图片数组（base64，未发送）
      selectedDocs: [],      // 已选文档数组 {name, base64}
      previewSrc: null,      // 图片预览模态框
      isRecording: false,   // 语音录音状态
      mediaRecorder: null,  // 媒体录制器
      audioChunks: []       // 录音数据块
    }
  },
  computed: {
    // 已选文件总数
    totalSelectedCount() {
      return this.selectedImages.length + this.selectedDocs.length
    }
  },
  mounted() {
    // 存储测试用户ID到Cookies
    this.$cookies.set('userId', this.userId, '7d')
    // 加载对话历史
    this.loadHistory()
  },
  methods: {
    // 加载对话历史
    async loadHistory() {
      try {
        const res = await this.$axios.get('/agent/history', {
          params: { userId: this.userId }
        })
        if (res.data.code === 200 && res.data.data) {
          // 将历史消息添加到消息列表
          res.data.data.forEach(msg => {
            this.msgList.push({
              isUser: msg.role === 'user',
              content: msg.content,
              images: [],
              docs: []
            })
          })
        }
      } catch (err) {
        console.error('加载历史失败:', err)
      }
    },
    // 触发上传（统一入口）
    triggerUpload() {
      this.$refs.uploadInput.click()
    },
    // 处理文件上传（图片+文档）
    handleFileUpload(event) {
      const files = event.target.files
      if (!files || files.length === 0) return
      
      let imageCount = this.selectedImages.length
      let docCount = this.selectedDocs.length
      
      for (let i = 0; i < files.length; i++) {
        const file = files[i]
        
        // 最多4张图片
        if (file.type.startsWith('image/') && imageCount < 4) {
          this.convertFileToBase64(file, (base64) => {
            this.selectedImages.push(base64)
          })
          imageCount++
        }
        // 最多2个文档
        else if (!file.type.startsWith('image/') && docCount < 2) {
          this.convertFileToBase64(file, (base64) => {
            this.selectedDocs.push({ name: file.name, base64: base64 })
          })
          docCount++
        }
        // 超出限制时提示
        else if (file.type.startsWith('image/') && imageCount >= 4) {
          this.$message && this.$message.warning('最多只能上传4张图片')
          break
        }
        else if (docCount >= 2) {
          this.$message && this.$message.warning('最多只能上传2个文档')
          break
        }
      }
      
      // 文件大小校验（图片10MB，文档20MB）
      for (let i = 0; i < files.length; i++) {
        const file = files[i]
        if (file.type.startsWith('image/') && file.size > 10 * 1024 * 1024) {
          this.$message && this.$message.warning('图片大小不能超过10MB')
          return
        }
        if (!file.type.startsWith('image/') && file.size > 20 * 1024 * 1024) {
          this.$message && this.$message.warning('文件大小不能超过20MB')
          return
        }
      }
      
      event.target.value = ''
    },
    // 移除已选图片
    removeImage(index) {
      this.selectedImages.splice(index, 1)
    },
    // 移除已选文档
    removeDoc(index) {
      this.selectedDocs.splice(index, 1)
    },
    // 文件转Base64
    convertFileToBase64(file, callback) {
      const reader = new FileReader()
      reader.onload = (e) => callback(e.target.result)
      reader.readAsDataURL(file)
    },
    // 语音输入（录音转文字需要后端ASR，这里仅做录音演示）
    async toggleVoice() {
      if (this.isRecording) {
        // 停止录音
        if (this.mediaRecorder) {
          this.mediaRecorder.stop()
          this.mediaRecorder.onstop = () => {
            const audioBlob = new Blob(this.audioChunks, { type: 'audio/webm' })
            this.audioChunks = []
            alert('语音已录制（ASR语音转文字功能待接入）')
          }
        }
        this.isRecording = false
      } else {
        // 开始录音
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ audio: true })
          this.mediaRecorder = new MediaRecorder(stream)
          this.audioChunks = []
          this.mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) this.audioChunks.push(e.data)
          }
          this.mediaRecorder.start()
          this.isRecording = true
        } catch (err) {
          alert('请允许麦克风权限后使用语音输入')
          console.error(err)
        }
      }
    },
    // 清除对话历史
    clearHistory() {
      if (confirm('确定要清除当前对话历史吗？')) {
        this.msgList = []
        // 调用后端清除历史
        this.$axios.post('/agent/clear-history', null, {
          params: { userId: this.userId }
        }).then(() => {
          this.$message && this.$message.success('对话历史已清除')
        }).catch(() => {
          // 后端未实现清除接口时静默失败
        })
      }
    },
    // 预览大图
    previewImage(src) {
      this.previewSrc = src
    },
    // 轻量markdown渲染（纯文本时原样输出，有markdown符号时转为HTML）
    renderMarkdown(text) {
      if (!text) return ''
      let html = text
        // 转义HTML特殊字符，防止XSS
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
      // 检查是否包含markdown标记
      const hasMd = /[#*`>\-_~\[!]/.test(text)
      if (!hasMd) return text  // 纯文本直接返回，不包裹html标签
      // 有markdown → 逐步转换
      html = html
        // 代码块 ```code``` → <pre><code>
        .replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>')
        // 行内代码 `code` → <code>
        .replace(/`([^`]+)`/g, '<code>$1</code>')
        // 标题 ### → <h3> (支持h1-h4)
        .replace(/^#### (.+)$/gm, '<h4>$1</h4>')
        .replace(/^### (.+)$/gm, '<h3>$1</h3>')
        .replace(/^## (.+)$/gm, '<h2>$1</h2>')
        .replace(/^# (.+)$/gm, '<h1>$1</h1>')
        // 粗斜体 ***text*** → <strong><em>
        .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
        // 粗体 **text** → <strong>
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        // 斜体 *text* → <em>（排除已处理的粗体）
        .replace(/(?<!\*)\*([^*]+)\*(?!\*)/g, '<em>$1</em>')
        // 引用 > text → <blockquote>
        .replace(/^&gt; (.+)$/gm, '<blockquote>$1</blockquote>')
        // 无序列表 - item / * item
        .replace(/^[\-*] (.+)$/gm, '<li>$1</li>')
        // 连续的<li>用<ul>包裹（简单处理）
        .replace(/(<li>.*<\/li>(\r?\n)?)+/g, '<ul>$&</ul>')
        // 段落分隔：两个以上换行
        .replace(/\n\n+/g, '</p><p>')
        // 单个换行 → <br>
        .replace(/\n/g, '<br>')
      return '<p>' + html + '</p>'
    },
    // 发送消息
    async sendMsg() {
      const text = this.inputContent.trim()
      const hasImages = this.selectedImages.length > 0
      const hasDocs = this.selectedDocs.length > 0
      
      if (!text && !hasImages && !hasDocs) {
        this.$message && this.$message.warning('请输入内容或选择图片/文件！')
        return
      }
      
      // 1. 添加用户消息到列表（带图片和文档预览）
      this.msgList.push({
        isUser: true,
        content: text || (hasDocs ? '(文件)' : '(图片)'),
        images: [...this.selectedImages],
        docs: [...this.selectedDocs]
      })
      
      const content = text
      const images = [...this.selectedImages]
      const docs = [...this.selectedDocs]
      
      this.inputContent = ''
      this.selectedImages = []
      this.selectedDocs = []
      
      // 2. 滚动到底部
      this.$nextTick(() => {
        const chatContent = document.getElementById('chatContent')
        chatContent.scrollTop = chatContent.scrollHeight
      })
      
      // 3. 调用后端接口（区分有图/有文档/纯文本）
      try {
        let res
        if (hasImages || hasDocs) {
          // 带图片或文档：使用FormData
          const formData = new FormData()
          formData.append('content', content)
          formData.append('userId', this.userId)
          // 发送第一张图片（多图可以循环发送或合并）
          if (hasImages) {
            formData.append('imageBase64', images[0])
          }
          res = await this.$axios.post('/agent/chat-with-image', formData, {
            headers: { 'Content-Type': 'multipart/form-data' }
          })
        } else {
          // 纯文本：保持原有逻辑
          res = await this.$axios.post('/agent/chat', null, {
            params: {
              content: content,
              userId: this.userId
            }
          })
        }
        if (res.data.code === 200) {
          // 4. 添加机器人消息到列表
          this.msgList.push({
            isUser: false,
            content: res.data.data.reply,
            data: res.data.data.data,
            intent: res.data.data.intent
          })
        } else {
          this.msgList.push({
            isUser: false,
            content: '服务出错了：' + res.data.msg
          })
        }
      } catch (err) {
        console.error(err)
        this.msgList.push({
          isUser: false,
          content: '网络出错了，请重试！'
        })
      } finally {
        // 5. 滚动到底部
        this.$nextTick(() => {
          const chatContent = document.getElementById('chatContent')
          chatContent.scrollTop = chatContent.scrollHeight
        })
      }
    }
  }
}
</script>

<style scoped>
.chat-box {
  background-color: #f8f9fa;
}
.chat-content {
  scroll-behavior: smooth;
}
/* AI消息markdown渲染样式 */
.ai-msg-content :deep(h1), .ai-msg-content :deep(h2),
.ai-msg-content :deep(h3), .ai-msg-content :deep(h4) {
  font-size: 1em;
  font-weight: bold;
  margin: 0.3em 0;
}
.ai-msg-content :deep(strong) { font-weight: bold; }
.ai-msg-content :deep(em) { font-style: italic; }
.ai-msg-content :deep(code) {
  background: #e9ecef;
  padding: 1px 4px;
  border-radius: 3px;
  font-size: 0.9em;
  color: #c7254e;
}
.ai-msg-content :deep(pre) {
  background: #212529;
  color: #f8f9fa;
  padding: 8px 12px;
  border-radius: 6px;
  overflow-x: auto;
  margin: 6px 0;
}
.ai-msg-content :deep(blockquote) {
  border-left: 3px solid #0d6efd;
  padding-left: 10px;
  margin: 6px 0;
  color: #495057;
}
.ai-msg-content :deep(ul) {
  padding-left: 18px;
  margin: 4px 0;
}
.ai-msg-content :deep(li) { margin: 2px 0; }
.ai-msg-content :deep(p) { margin: 2px 0; }
/* 扩展菜单样式 */
.dropdown-menu {
  border: none;
  border-radius: 12px;
  padding: 6px;
  box-shadow: 0 4px 16px rgba(0,0,0,0.12);
  font-size: 14px;
}
.dropdown-item {
  border-radius: 8px;
  transition: background 0.15s;
}
.dropdown-item:hover {
  background-color: #f0f2f5;
}
.dropdown-item:active {
  background-color: #e4e6eb;
}
.dropdown-divider {
  margin: 4px 0;
}
</style>
